import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PriceTrend {
  day: string;
  price: number;
}

interface GasData {
  location: string;
  averagePrice: number;
  cheapestNearby: {
    station: string;
    price: number;
    address: string;
  };
  priceTrend: PriceTrend[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const gasData = response.data as GasData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#2E3B4E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {gasData.location}
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#FFC107', my: 0.5 }}>
              Average: ${gasData.averagePrice.toFixed(2)}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Cheapest: {gasData.cheapestNearby.station} - ${gasData.cheapestNearby.price.toFixed(2)}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {gasData.cheapestNearby.address}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: gasData.priceTrend.map(pt => pt.price),
                  color: metaData.primaryColor,
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: gasData.priceTrend.map(pt => pt.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'price', min: Math.min(...gasData.priceTrend.map(pt => pt.price)) - 0.05 }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="price"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
